{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is the classical textbook example of the Ritter reaction, featuring the reaction of tert-butanol with acetonitrile in the presence of a strong acid (sulfuric acid). The tert-butanol serves as a stable precursor to the tert-butyl carbocation, which is then trapped by the nitrile. Subsequent hydrolysis of the resulting nitrilium ion intermediate yields N-tert-butylacetamide. All reactants and the product are simple, acyclic, and lack complex functional groups, making this a clear and unambiguous representation of the core transformation.",
    "collision_avoidance_note": "This example uses simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with reactions involving aromatic rings (e.g., Friedel-Crafts), complex rearrangements, or other named reactions that might also involve carbocations or nitriles in different contexts. The transformation is a straightforward addition of a carbocation and water across a nitrile triple bond, which is the defining feature of the Ritter reaction."
  }
}
